int main() {
    const std::filesystem::path log_dir = std::filesystem::temp_directory_path() / "werewolf_log_overflow_test";
    std::filesystem::create_directories(log_dir);
    const std::filesystem::path log_file = log_dir / "overflow.log";

    if (!Log::get_instance()->init(log_file.string().c_str(), kLogBufferSize, 1000, 0)) {
        throw std::runtime_error("failed to initialize test log file");
    }

    const std::string prefix =
        "[LOG_OVERFLOW_TEST] This line should exceed the internal log buffer. "
        "If the old implementation is still present, this kind of input may corrupt memory before the next network call. ";

    const std::string payload = prefix + kManualLongPayload + "\n" + kManualLongPayload + "\n" + kManualLongPayload;

    std::cout << "Writing payload with " << payload.size() << " bytes into log buffer " << kLogBufferSize << "..." << std::endl;
    Log::get_instance()->write_log(1, "%s", payload.c_str());
    Log::get_instance()->flush();

    std::cout << "Completed without crashing. Check log file: " << log_file << std::endl;
    return 0;
}
